const body = $input.first().json.body || $input.first().json;
const own_profile_id = body.own_profile_id;

if (!own_profile_id) throw new Error('Missing required field: own_profile_id');
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(own_profile_id)) {
  throw new Error('own_profile_id must be a valid UUID');
}

return [{ json: { own_profile_id } }];

// Merge own posts and competitor list, validate we have enough, build competitor IDs for next query
const ownRaw = $('Fetch Own Posts').first().json;
const compRaw = $('Fetch Competitors').first().json;

const own_posts = Array.isArray(ownRaw) ? ownRaw : [ownRaw];
const competitors = Array.isArray(compRaw) ? compRaw : [compRaw];

const own_profile_id = $('Validate Input').first().json.own_profile_id;

if (competitors.length < 2) {
  throw new Error(`Need at least 2 competitor profiles. Found: ${competitors.length}. Add and scrape competitors first.`);
}

// Build comma-separated IDs for Supabase IN filter
const competitor_ids = competitors.map(c => c.id);

return [{ json: { own_profile_id, own_posts, competitors, competitor_ids } }];

function sanitize(str) {
  if (!str) return '';
  return str.replace(/[\uD800-\uDFFF]/g, '').replace(/[\x00-\x1F\x7F]/g, ' ').trim();
}

function formatPosts(posts, limit) {
  if (!posts || posts.length === 0) return '  (no posts scraped yet)';
  return posts.slice(0, limit).map((p, i) => {
    const caption = sanitize(p.caption || '').slice(0, 100);
    const date = (p.posted_at || '').slice(0, 10);
    return `  ${String(i+1).padStart(2)}. [${(p.content_type||'unknown').padEnd(8)}] ${date} | L:${p.likes||0} C:${p.comments||0} V:${p.views||0} | "${caption}"`;
  }).join('\n');
}

const upstream = $('Merge Profiles').first().json;
const { own_profile_id, own_posts, competitors } = upstream;

// Get all competitor posts and group by profile_id
const allPostsRaw = $input.first().json;
const allPosts = Array.isArray(allPostsRaw) ? allPostsRaw : [allPostsRaw];

// Build a map: profile_id -> posts[]
const postsByProfile = {};
for (const post of allPosts) {
  if (!postsByProfile[post.profile_id]) postsByProfile[post.profile_id] = [];
  postsByProfile[post.profile_id].push(post);
}

const competitorCount = competitors.length;

// Format sections for Claude prompt
const ownSection = `--- OWN ACCOUNT (${own_posts.length} posts, top by likes) ---\n${formatPosts(own_posts, 30)}`;

let competitorSections = '';
for (const comp of competitors) {
  const posts = postsByProfile[comp.id] || [];
  competitorSections += `\n--- COMPETITOR: @${comp.username} (${posts.length} posts) ---\n${formatPosts(posts, 50)}\n`;
}

const systemPrompt = `You are a social media growth analyst specialising in Instagram content strategy. Analyze all provided posts and detect content patterns that consistently outperform average engagement. Return ONLY a valid JSON array, no markdown, no code blocks, no explanation outside the JSON. Be extremely specific in mega_tip recommendations — tell the creator exactly what video to make, what hook to use in the first 3 seconds, caption structure, and best posting day/time.`;

const userPrompt = `Analyze the following Instagram posts from ${competitorCount} competitor accounts plus the user's own account.

IDENTIFY CONTENT PATTERNS across all accounts. Consider patterns such as: episodic series, problem/solution, gear review, montage/recap, origin story, vulnerability/personal story, human connection moment, educational how-to, food and culture, scenic adventure, behind-the-scenes, challenge/transformation, Q&A, day-in-life, gear failure/mistake, achievement celebration, myth-busting, comparison, route/destination reveal.

For EACH pattern identified:
1. Determine which competitors have it in their TOP 20% posts by likes
2. Only include the pattern if it appears in top 20% posts of 2+ competitors (VALIDATED TREND)
3. Calculate performance_multiplier = average likes of posts with this pattern / average likes of all posts for that competitor

${ownSection}
${competitorSections}

Return a JSON ARRAY (3–7 items max), sorted by performance_multiplier descending. Each item MUST have exactly this structure:
{
  "trend_name": "Short descriptive name like 'Episodic Series Content'",
  "confidence": "X/${competitorCount} competitors",
  "performance_multiplier": 3.2,
  "why_it_works": "1-2 sentences explaining the psychological/algorithmic reason this pattern drives engagement",
  "example_posts": [
    {"caption_preview": "first 80 chars of caption", "likes": 1234, "comments": 56, "competitor": "@username"},
    {"caption_preview": "...", "likes": 890, "comments": 34, "competitor": "@username"},
    {"caption_preview": "...", "likes": 567, "comments": 23, "competitor": "@username"}
  ],
  "mega_tip": "VERY SPECIFIC instruction: describe exactly what to film, the opening hook line word-for-word, caption structure with example hashtags, and ideal posting day and time. Minimum 3 sentences.",
  "user_doing_it": true
}

Critical rules:
- performance_multiplier must be a number, not a string
- example_posts must have exactly 3 entries
- user_doing_it must be a boolean (true if own account posts clearly show this pattern, false otherwise)
- Return ONLY the JSON array`;

return [{ json: { own_profile_id, system_prompt: systemPrompt, user_prompt: userPrompt, competitor_count: competitorCount } }];

const resp = $input.first().json;
const rawText = resp?.content?.[0]?.text;
if (!rawText) throw new Error('Claude returned no content. Response: ' + JSON.stringify(resp));

const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let trends;
try {
  trends = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude JSON: ' + e.message + '\nRaw: ' + cleaned.slice(0, 500));
}

if (!Array.isArray(trends)) throw new Error('Expected JSON array from Claude, got: ' + typeof trends);

const upstream = $('Build Claude Prompt').first().json;
const own_profile_id = upstream.own_profile_id;

const enriched = trends.map(t => ({
  profile_id: own_profile_id,
  trend_name: t.trend_name || 'Unknown Trend',
  confidence: (() => {
    const parts = String(t.confidence || '0/1').split('/');
    return parseFloat(parts[0]) / (parseFloat(parts[1]) || 1);
  })(),
  confidence_label: t.confidence || '',
  performance_multiplier: typeof t.performance_multiplier === 'number' ? t.performance_multiplier : parseFloat(t.performance_multiplier) || 0,
  why_it_works: t.why_it_works || '',
  example_posts: JSON.stringify(t.example_posts || []),
  recommendation: t.mega_tip || '',
  suggested_schedule: '',
  is_mega_tip: t.user_doing_it === false && (t.performance_multiplier || 0) > 2,
  user_doing_it: t.user_doing_it === true
}));

console.log(`Parsed ${enriched.length} trends. Mega-tips: ${enriched.filter(t => t.is_mega_tip).length}`);

return enriched.map(r => ({ json: r }));

const allInserted = $input.all();
const upstream = $('Parse & Enrich Response').all();

const megaTips = upstream.filter(i => i.json.is_mega_tip).length;
const total = upstream.length;

return [{
  json: {
    success: true,
    trends_detected: total,
    mega_tips: megaTips,
    insights: upstream.map(i => ({
      trend_name: i.json.trend_name,
      confidence_label: i.json.confidence_label,
      performance_multiplier: i.json.performance_multiplier,
      is_mega_tip: i.json.is_mega_tip,
      user_doing_it: i.json.user_doing_it
    }))
  }
}];
